      expect(columns).toContain("agentId");
      expect(columns).toContain("contextClassification");
      expect(columns).toContain("allowlisted");
      expect(columns).toContain("updatedAt");
      logger.info({ columns, testName: "column_existence" }, "Verified DCG blocks columns");
    });

