  content: string | ToolUseContent | ToolResultContent;
  metadata?: {
    tokenCount?: number;
    toolName?: string;
    executionMs?: number;
  };
}

// Usage
for await (const chunk of driver.getOutput(agentId, lastCursor)) {
  // Process chunk
  lastCursor = chunk.cursor;
}
```

### Event System

```typescript
type DriverEvent = 
  | 'agent:spawning'
  | 'agent:ready'
  | 'agent:executing'
  | 'agent:paused'
  | 'agent:terminated'
  | 'agent:error'
